use actix_web::{web, HttpResponse};
use sqlx::PgPool;
use crate::models::Invoice;

async fn get_invoice_details(pool: web::Data<PgPool>, id: web::Path<i32>) -> Result<HttpResponse, actix_web::Error> {
    let invoice_id = id.into_inner();
    let user_id = request().extensions().get::<i32>().unwrap();

    match sqlx::query("SELECT * FROM invoices WHERE id = $1 AND user_id = $2")
        .bind(invoice_id)
        .bind(user_id)
        .fetch_one(pool.get_ref())
        .await
    {
        Ok(invoice) => Ok(HttpResponse::Ok().json(Invoice::from_db(invoice))),
        Err(_) => Err(actix_web::error::ErrorNotFound("Invoice not found")),
    }
}

pub fn configure(cfg: &mut web::ServiceConfig) {
    cfg.service(
        web::scope("/invoices")
            .service(web::resource("{id}").route(web::get().to(get_invoice_details))),
    );
}